BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name WHERE {
  # Find the root TMT package
  ?root vocab:NamedElement_name "TMT" .

  # Find packages directly owned by TMT (first-level children)
  { ?root vocab:Element_ownedElement ?pkg . }
  UNION
  # Also find top-level packages (those with no owner or owned by another top-level package)
  { ?pkg vocab:Element_owner ?owner .
    FILTER NOT EXISTS { ?owner vocab:Element_owner ?grandowner }
  }

  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?name WHERE {
  # Find packages that have no owner (top-level packages)
  ?pkg rdf:type vocab:package .

  FILTER NOT EXISTS { ?pkg vocab:Element_owner ?owner }

  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
}
ORDER BY ?name
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?owner WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?name .
  OPTIONAL { ?pkg vocab:Element_owner ?owner }
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
}
ORDER BY ?ownerName ?name
LIMIT 50
